#include <stdio.h>

long long countPairs(int arr[], int n, int x) {
    long long cnt = 0;
    int l = 0, r = n - 1;
    while (l < r) {
        if (arr[l] + arr[r] < x) {
            cnt += (r - l);
            ++l;
        } else {
            --r;
        }
    }
    return cnt;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, x;
        scanf("%d", &n);
        int arr[100000];
        for (int i = 0; i < n; ++i) {
            scanf("%d", &arr[i]);
        }
        scanf("%d", &x);
        printf("%lld\n", countPairs(arr, n, x));
    }
    return 0;
}

