import sys

def count_pairs(arr, x):
    cnt = 0
    l, r = 0, len(arr) - 1
    while l < r:
        if arr[l] + arr[r] < x:
            cnt += r - l
            l += 1
        else:
            r -= 1
    return cnt

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        x = int(next(it))
        out.append(str(count_pairs(arr, x)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

